import { writeOutput } from "./codegen";

const DOCS_URL = "https://coda.io/developers/apis/v1";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Coda API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:coda",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const codaFirewall = {",
    '  name: "coda",',
    '  description: "Coda",',
    "  placeholders: {",
    `    CODA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://coda.io",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.CODA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Coda firewall config...");
  const ts = generateTypeScript();
  writeOutput("coda", ts, import.meta.dirname);
}
